import{_ as r,C as s,o,c as l,E as t,w as i,a as n,a0 as d}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Germany Legal Rights","description":"Legal rights for transgender people in Germany","frontmatter":{"layout":"doc","title":"Germany Legal Rights","description":"Legal rights for transgender people in Germany"},"headers":[],"relativePath":"europe/germany/legal-rights.md","filePath":"europe/germany/legal-rights.md","lastUpdated":null}'),c={name:"europe/germany/legal-rights.md"};function h(g,e,m,p,u,f){const a=s("Badge");return o(),l("div",null,[t(a,{variant:"yellow"},{default:i(()=>[...e[0]||(e[0]=[n("Self-Determination Act since 2025",-1)])]),_:1}),t(a,{variant:"green"},{default:i(()=>[...e[1]||(e[1]=[n("Hate Crime Protections",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="legal-rights-in-germany" tabindex="-1">Legal Rights in Germany <a class="header-anchor" href="#legal-rights-in-germany" aria-label="Permalink to &quot;Legal Rights in Germany&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Germany&#39;s Self-Determination Act (Selbstbestimmungsgesetz, SBGG) took effect in 2025, replacing the outdated Transsexuellengesetz (TSG). The SBGG allows adults to change their legal gender and first name through a simple self-declaration at the Standesamt (civil registry office). No medical reports, court orders, or psychological evaluations are required.</p><p>A three-month waiting period applies before the declaration takes effect. The process costs approximately €30-60. For minors under 14, parents must submit the declaration. Minors aged 14-17 can submit with parental consent.</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><p>Name changes are handled through the same Standesamt application as gender recognition. You can change your first name(s) to match your gender identity. Multiple names can be selected. The process takes 1-3 months total including the waiting period.</p><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>The General Equal Treatment Act (AGG) prohibits discrimination based on gender identity in:</p><ul><li><strong>Employment</strong>: All phases including hiring and dismissal</li><li><strong>Goods and services</strong>: Housing, banking, healthcare</li><li><strong>Education</strong>: Access to schools and universities</li></ul><p>The Federal Anti-Discrimination Agency (ADS) provides support and mediation.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><p>Gender identity is recognised as a hate crime motivation under German law. Section 46 of the Criminal Code treats transphobic motives as aggravating factors in sentencing. The police have dedicated LGBTQ+ liaison officers in major cities.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.bundesverband-trans.de/" target="_blank" rel="noreferrer">Bundesverband Trans</a> — National trans advocacy</li><li><a href="https://www.lsvd.de/" target="_blank" rel="noreferrer">LSVD</a> — LGBTQ+ legal support</li><li><a href="https://www.antidiskriminierungsstelle.de/" target="_blank" rel="noreferrer">Federal Anti-Discrimination Agency</a> — File complaints</li></ul>',14))])}const w=r(c,[["render",h]]);export{y as __pageData,w as default};
